using UnityEngine; using UnityEngine.UI; using NabyeolDabyeolDreamPuzzle.Stage;
namespace NabyeolDabyeolDreamPuzzle.UI { public class ResultPopupController:MonoBehaviour{ [SerializeField] GoalManager goalManager; [SerializeField] GameObject clearPopup,failPopup; [SerializeField] Button clearNextButton,clearStageSelectButton,failRetryButton,failStageSelectButton; void Awake(){ goalManager??=FindAnyObjectByType<GoalManager>(); HideAllPopups(); } void OnEnable(){ if(goalManager!=null){ goalManager.OnStageCleared+=ShowClearPopup; goalManager.OnStageFailed+=ShowFailPopup; }} void OnDisable(){ if(goalManager!=null){ goalManager.OnStageCleared-=ShowClearPopup; goalManager.OnStageFailed-=ShowFailPopup; }} public void ShowClearPopup(){HideAllPopups(); if(clearPopup) clearPopup.SetActive(true);} public void ShowFailPopup(){HideAllPopups(); if(failPopup) failPopup.SetActive(true);} public void HideAllPopups(){ if(clearPopup)clearPopup.SetActive(false); if(failPopup)failPopup.SetActive(false);} } }
